+  private getCursorPagination(opts: CrudOptions): {
+    orderBy: { field: string; direction: 'asc' | 'desc' }[];
+    cursor?: Record<string, any>;
+  } | null {
+    if (opts.cursor === undefined) {
+      return opts.orderBy && opts.limit
+        ? { orderBy: this.getCursorOrderBy(opts.orderBy) }
+        : null;
+    }
+
+    if (!opts.orderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (opts.offset !== undefined) {
+      throw new BadRequestException('cursor cannot be used with offset');
+    }
+
+    const orderBy = this.getCursorOrderBy(opts.orderBy);
+    const cursor = this.decodeCursor(opts.cursor);
+    const expectedSort = orderBy
+      .map(({ field, direction }) => `${field}:${direction}`)
+      .join(',');
+    if (cursor.__sort !== expectedSort) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+
+    const idField = this.crudConfig.id_field;
+    if (!Object.prototype.hasOwnProperty.call(cursor, idField)) {
+      throw new BadRequestException('cursor is missing the entity ID');
+    }
+    for (const { field } of orderBy) {
+      if (!Object.prototype.hasOwnProperty.call(cursor, field)) {
+        throw new BadRequestException(`cursor is missing sort field ${field}`);
+      }
+    }
+
+    return { orderBy, cursor };
+  }
+
+  private getCursorOrderBy(orderBy: CrudOptions['orderBy']) {
+    const order: { field: string; direction: 'asc' | 'desc' }[] = [];
+    for (const item of Array.isArray(orderBy) ? orderBy : [orderBy]) {
+      for (const [field, value] of Object.entries(item || {})) {
+        const direction = String(value).toLowerCase().startsWith('desc')
+          ? 'desc'
+          : 'asc';
+        order.push({ field, direction });
+      }
+    }
+    if (!order.length) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    const idField = this.crudConfig.id_field;
+    if (!order.some(({ field }) => field === idField)) {
+      order.push({ field: idField, direction: 'asc' });
+    }
+    return order;
+  }
+
+  private decodeCursor(cursor: string): Record<string, any> {
+    try {
