import { OpParams } from "@eicrud/core/crud";

const query: Partial<Profile> = {
    astroSign: "Aries"
}

const opParams: OpParams = {
    options: {
        limit: 20
    }
}

const {data, total, limit} = await profileService.$find(query, null, opParams);
